import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";const i=JSON.parse(`{"title":"Nahrávání logů","description":"Jak nahrávat logy pro řešení problémů.","frontmatter":{"title":"Nahrávání logů","description":"Jak nahrávat logy pro řešení problémů.","authors":["IMB11"],"files":[]},"headers":[],"relativePath":"cs_cz/players/troubleshooting/uploading-logs.md","filePath":"translated/cs_cz/players/troubleshooting/uploading-logs.md","lastUpdated":1770561656000}`);var a={name:`cs_cz/players/troubleshooting/uploading-logs.md`};function o(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Nahrávání logů <a class="header-anchor" href="#h1" aria-label="Permalink to “Nahrávání logů”">​</a></h1><p>Při řešení problémů je pro vyhledání příčiny často nutné poskytnout logy.</p><h2 id="why-should-i-upload-logs" tabindex="-1">Proč bych měl nahrávat logy? <a class="header-anchor" href="#why-should-i-upload-logs" aria-label="Permalink to “Proč bych měl nahrávat logy?”">​</a></h2><p>Nahrávání logů pomáhá ostatním poskytnout ti pomoc rychleji než jednoduše vložením logů do chatu nebo příspěvku na fóru. Také ti to umožňuje sdílet logy s ostatními bez nutnosti je kopírovat a vkládat.</p><p>Některé stránky speciálně určené pro vkládání logů poskytují zvýraznění syntaxu logů tak, aby se lépe četly, nebo cenzuru citlivých informací, jako uživatelského jména nebo systémových informací.</p><h2 id="crash-reports" tabindex="-1">Hlášení o chybách <a class="header-anchor" href="#crash-reports" aria-label="Permalink to “Hlášení o chybách”">​</a></h2><p>Hlášení o chybách je automaticky vygenerováno při spadnutí hry. Obsahují pouze informace o chybě, ne logy ze hry. Nachází se ve složce <code>crash-reports</code> v adresáři hry.</p><p>Více informací o hlášeních o chybách vám poskytne tutoriál o <a href="./crash-reports">hlášeních o chybách</a>.</p><h2 id="locating-logs" tabindex="-1">Vyhledávání logů <a class="header-anchor" href="#locating-logs" aria-label="Permalink to “Vyhledávání logů”">​</a></h2><p>Tenhle tutoriál je určen pouze pro oficiální Minecraft Launcher (také znám pod názvem &quot;vanilla launcher&quot;) - u neoficiálních launcherů navštivte jejich dokumentaci.</p><p>Logy se nacházejí ve složce <code>logs</code> v adresáři hry; ten lze dle operačního systému najít v následujících lokacích:</p><div class="vp-code-group"><div class="tabs"><input type="radio" name="group-33" id="tab-34" checked><label data-title="Windows" for="tab-34">Windows</label><input type="radio" name="group-33" id="tab-35"><label data-title="macOS" for="tab-35">macOS</label><input type="radio" name="group-33" id="tab-36"><label data-title="Linux" for="tab-36">Linux</label></div><div class="blocks"><div class="language-text active"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>%appdata%\\.minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/Library/Application Support/minecraft</span></span></code></pre></div><div class="language-text"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>~/.minecraft</span></span></code></pre></div></div></div><p>Nejnovější log se jmenuje <code>latest.log</code>, předchozí logy jsou pojmenovávány pomocí schématu <code>yyyy-mm-dd_number.log.gz</code>.</p><h2 id="uploading-logs-online" tabindex="-1">Nahrávání logů online <a class="header-anchor" href="#uploading-logs-online" aria-label="Permalink to “Nahrávání logů online”">​</a></h2><p>Logy lze nahrát na mnoho stránek, jako jsou:</p><ul><li><a href="https://pastebin.com/" target="_blank" rel="noreferrer">Pastebin</a></li><li><a href="https://gist.github.com/" target="_blank" rel="noreferrer">GitHub Gist</a></li><li><a href="https://mclo.gs/" target="_blank" rel="noreferrer">mclo.gs</a></li></ul>`,16)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};